import{r as a,o,c as r,a as e,f as t,F as i,d as n,h as c}from"./app.c91ba1df.js";import{_ as p}from"./plugin-vue_export-helper.21dcd24c.js";const l={},d=e("h1",{id:"web-2475-\u2014-xray-api-for-test-executions-in-jira-snapshots-spike-outcome",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#web-2475-\u2014-xray-api-for-test-executions-in-jira-snapshots-spike-outcome","aria-hidden":"true"},"#"),n(" WEB-2475 \u2014 Xray API for Test Executions in Jira Snapshots (Spike Outcome)")],-1),u=e("strong",null,"Ticket:",-1),h=n(),g={href:"https://sanofi.atlassian.net/browse/WEB-2475",target:"_blank",rel:"noopener noreferrer"},k=n("WEB-2475"),m=n(" (Spike) \u2014 "),f=e("em",null,"Implement XRAY API on Konviw to handle Test executions on Jira Snapshot",-1),y=e("strong",null,"Feeds:",-1),v=n(),b={href:"https://sanofi.atlassian.net/browse/JPDST-58",target:"_blank",rel:"noopener noreferrer"},q=n("JPDST-58"),_=n(" \u2014 "),T=e("em",null,'Support of "jira snapshot" in konviw',-1),x=e("li",null,[e("strong",null,"Status:"),n(" Feasibility confirmed and validated "),e("strong",null,"live"),n(" against production Xray.")],-1),A=c(`<h2 id="question" tabindex="-1"><a class="header-anchor" href="#question" aria-hidden="true">#</a> Question</h2><p>A Jira Snapshot&#39;s last level does <strong>not</strong> use the Jira API to fetch data \u2014 it uses the <strong>Xray API</strong>. Can konviw implement the Xray API to render that level (test executions / test runs)?</p><h2 id="answer" tabindex="-1"><a class="header-anchor" href="#answer" aria-hidden="true">#</a> Answer</h2><p><strong>Yes.</strong> Implemented, unit-tested, and validated end-to-end through the real konviw server against production Xray Cloud.</p><h2 id="background" tabindex="-1"><a class="header-anchor" href="#background" aria-hidden="true">#</a> Background</h2><p>The <code>jira-jql-snapshot</code> macro defines a list of <code>levels</code>. Each level has a <code>levelType</code>:</p><ul><li><code>JIRA_ISSUES</code> \u2014 data comes from the Jira REST API (already supported by konviw).</li><li><code>XRAY_TESTRUNS</code> \u2014 data comes from the <strong>Xray Cloud GraphQL API</strong>, not Jira. This is the level that was previously unsupported (rendered a &quot;not supported&quot; placeholder).</li></ul><p>Real level structure observed on the TRACK4 release report (page <code>64358745517</code>):</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;title&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Test execution&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;jql&quot;</span><span class="token operator">:</span> <span class="token string">&quot;mode = all AND fixVersions = Track4 2.0.1 AND environments = Test&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;fieldsPosition&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
    <span class="token punctuation">{</span> <span class="token property">&quot;label&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Test Execution Key&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;value&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;testexeckey&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">{</span> <span class="token property">&quot;label&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Status&quot;</span><span class="token punctuation">,</span>             <span class="token property">&quot;value&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;status&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">{</span> <span class="token property">&quot;label&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Fix versions&quot;</span><span class="token punctuation">,</span>       <span class="token property">&quot;value&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;fixversions&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">{</span> <span class="token property">&quot;label&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Defects&quot;</span><span class="token punctuation">,</span>            <span class="token property">&quot;value&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;defects&quot;</span> <span class="token punctuation">}</span> <span class="token punctuation">}</span>
  <span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token property">&quot;levelType&quot;</span><span class="token operator">:</span> <span class="token string">&quot;XRAY_TESTRUNS&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>Hierarchy: <strong>Requirements \u2192 Test Cases (<code>issuetype = Test</code>) \u2192 Test execution (Xray)</strong>.</p><h2 id="approach" tabindex="-1"><a class="header-anchor" href="#approach" aria-hidden="true">#</a> Approach</h2><ul><li><strong><code>src/xray/xray.service.ts</code></strong> \u2014 Xray Cloud client: <ul><li>Authenticates with <code>client_id</code> / <code>client_secret</code> \u2192 bearer token (<code>POST /authenticate</code>), cached ~23h.</li><li><code>getTestRunsByTestIds(testIds)</code> runs a GraphQL <code>getTestRuns(testIssueIds: [...])</code> query with pagination (Xray caps <code>limit</code> at 100).</li></ul></li><li><strong><code>src/xray/xray.module.ts</code></strong> \u2014 module with its own <code>HttpModule</code> (avoids the Jira basic-auth interceptor).</li><li><strong><code>src/proxy-page/steps/addJiraSnapshot.ts</code></strong> \u2014 for an <code>XRAY_TESTRUNS</code> level: <ol><li>Take the parent Tests&#39; Jira issue ids from the previous level.</li><li>Fetch their test runs via <code>XrayService</code>.</li><li>Apply a best-effort <strong>fix-version filter</strong> parsed from the level&#39;s query.</li><li>Group runs by <code>run.test.issueId</code> (nesting under the parent Test).</li><li>Map each run onto the macro&#39;s configured column ids (<code>testexeckey</code>, <code>status</code>, <code>fixversions</code>, <code>defects</code>, and a supported superset) and render through the existing Grid.js pipeline.</li></ol></li><li><strong>Config</strong> (<code>src/config/configuration.ts</code>): <ul><li><code>CPV_XRAY_BASE_URL</code> (default <code>https://xray.cloud.getxray.app/api/v2</code>)</li><li><code>CPV_XRAY_CLIENT_ID</code></li><li><code>CPV_XRAY_CLIENT_SECRET</code></li></ul></li></ul><h2 id="when-it-runs-gating" tabindex="-1"><a class="header-anchor" href="#when-it-runs-gating" aria-hidden="true">#</a> When it runs (gating)</h2><p>The Xray API is called <strong>only</strong> for pages that contain a <code>jira-jql-snapshot</code> macro <strong>with an <code>XRAY_TESTRUNS</code> level</strong>. It runs on-demand during a page render \u2014 not as a background scan.</p><table><thead><tr><th>Page</th><th>Xray API called?</th></tr></thead><tbody><tr><td>No Jira Snapshot macro</td><td>No \u2014 snapshot processing skipped entirely</td></tr><tr><td>Snapshot with only <code>JIRA_ISSUES</code> levels</td><td>No \u2014 Jira API only, unchanged behaviour</td></tr><tr><td>Snapshot with an <code>XRAY_TESTRUNS</code> level</td><td>Yes \u2014 that level triggers the Xray query</td></tr></tbody></table><p>Safety: if credentials are not configured or the call fails, the service returns an empty list and the page still renders (graceful degradation).</p><h2 id="validation" tabindex="-1"><a class="header-anchor" href="#validation" aria-hidden="true">#</a> Validation</h2><ul><li><strong>Unit tests:</strong> <code>tests/unit/xray/xray.service.spec.ts</code>, <code>tests/unit/steps/addJiraSnapshot.spec.ts</code> (auth, batching/pagination, grouping, filtering, graceful degradation, rendering).</li><li><strong>Live, end-to-end</strong> through the real konviw server against the TRACK4 release report (<code>/cpv/wiki/spaces/TRACK4/pages/64358745517</code>): <ul><li><code>Retrieved 247 Xray test runs for 86 test(s)</code> from production Xray Cloud.</li><li>Rendered <strong>Requirements (21) \u2192 Test Cases (86) \u2192 Test execution (224 after fix-version filter)</strong> with correct execution keys, colored status lozenges, fix versions, and defect links.</li></ul></li></ul><h2 id="key-findings-corrections" tabindex="-1"><a class="header-anchor" href="#key-findings-corrections" aria-hidden="true">#</a> Key findings / corrections</h2><ul><li>The level&#39;s <strong>columns are macro-defined</strong> (<code>testexeckey</code>, <code>status</code>, <code>fixversions</code>, <code>defects</code>) \u2014 not a fixed set. The implementation honours whatever the macro configures.</li><li>The Xray level <strong>nests under the parent Test</strong> (<code>run.test</code>), not under a Test Execution.</li><li>The level carries its <strong>own Xray query</strong> (<code>mode / fixVersions / environments</code>), not a <code>$key</code> reference to the parent.</li><li>Xray&#39;s GraphQL <code>TestRun</code> type has <strong>no <code>testEnvironments</code> field</strong> (test environments live on the Test Execution). Querying it returns HTTP 400; it was removed from the query.</li></ul><h2 id="open-items-not-blocking-feasibility" tabindex="-1"><a class="header-anchor" href="#open-items-not-blocking-feasibility" aria-hidden="true">#</a> Open items (not blocking feasibility)</h2><ul><li><strong><code>environments = Test</code> filter</strong> is not applied \u2014 would require fetching the Test Execution&#39;s <code>testEnvironments</code>. Currently only <code>fixVersions</code> is filtered.</li><li><strong><code>mode = all</code></strong> semantics \u2014 appears to mean &quot;all runs&quot; (consistent with the page&#39;s own note that TODO executions cannot be removed); to confirm with Xray/Kevin.</li><li><strong>Production rollout:</strong> set <code>CPV_XRAY_*</code> env vars in the deployment environment. A dedicated <strong>service account</strong> is recommended (see Kevin&#39;s page below); today it uses a personal Jira API token for the Jira side.</li></ul><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references" aria-hidden="true">#</a> References</h2><ul><li>Kevin Paugam \u2014 <em>Jira and Xray</em> connection guide: <code>MSPROD/66101249623</code></li><li>TRACK4 release report (real macroParams + live validation): <code>TRACK4/64358745517</code></li><li>Xray Cloud GraphQL API: https://docs.getxray.app/display/XRAYCLOUD/GraphQL+API</li></ul><h2 id="recommendation" tabindex="-1"><a class="header-anchor" href="#recommendation" aria-hidden="true">#</a> Recommendation</h2><p>Feasibility is confirmed with a working, live-validated implementation. To productionize: merge the branch, set the prod Xray credentials, and optionally add environment-based filtering if required for these reports.</p>`,26);function S(R,w){const s=a("ExternalLinkIcon");return o(),r(i,null,[d,e("ul",null,[e("li",null,[u,h,e("a",g,[k,t(s)]),m,f]),e("li",null,[y,v,e("a",b,[q,t(s)]),_,T]),x]),A],64)}var E=p(l,[["render",S]]);export{E as default};
